import{_ as a,o,c as l,a0 as r}from"./chunks/framework.CDWbKMqd.js";const p=JSON.parse('{"title":"微调应该用在哪里","description":"","frontmatter":{"title":"微调应该用在哪里","date":"2026-07-24T00:00:00.000Z","category":"tech","tags":["AI","模型微调","RAG","强化学习"],"summary":"RAG 已经这么方便了，微调到底还有什么用？记录一次讨论：RAG 教模型\\"知道什么\\"，微调教模型\\"怎么做\\"；工作流是棋谱，训练是下一万盘棋内化出的棋感。"},"headers":[],"relativePath":"posts/finetune-vs-rag-vs-workflow.md","filePath":"posts/finetune-vs-rag-vs-workflow.md"}'),e={name:"posts/finetune-vs-rag-vs-workflow.md"};function i(s,t,d,n,h,u){return o(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="微调到底有什么用-——一次关于-rag、rl-与工作流的问答记录" tabindex="-1">微调到底有什么用？——一次关于 RAG、RL 与工作流的问答记录 <a class="header-anchor" href="#微调到底有什么用-——一次关于-rag、rl-与工作流的问答记录" aria-label="Permalink to &quot;微调到底有什么用？——一次关于 RAG、RL 与工作流的问答记录&quot;">​</a></h1><p>最近参加数字马力培训，学到强化学习时展开的一次讨论。 围绕一个核心问题展开：RAG 比微调更实际，那真正要用微调的地方到底在哪里？以下按问答整理。</p><h2 id="q1-rag-比微调更实际-真正要用模型微调的地方到底在哪里" tabindex="-1">Q1：RAG 比微调更实际，真正要用模型微调的地方到底在哪里？ <a class="header-anchor" href="#q1-rag-比微调更实际-真正要用模型微调的地方到底在哪里" aria-label="Permalink to &quot;Q1：RAG 比微调更实际，真正要用模型微调的地方到底在哪里？&quot;">​</a></h2><p>核心结论：<strong>RAG 教模型&quot;知道什么&quot;，微调教模型&quot;怎么做&quot;。</strong></p><ul><li>RAG 适合：频繁变化的知识、事实性查询、可审计性要求高、数据分散</li><li>微调适合：风格/语调内化、推理模式迁移、任务一致性、领域直觉的培养</li></ul><h2 id="q2-rl-和其他推理方法的差别与选择" tabindex="-1">Q2：RL 和其他推理方法的差别与选择？ <a class="header-anchor" href="#q2-rl-和其他推理方法的差别与选择" aria-label="Permalink to &quot;Q2：RL 和其他推理方法的差别与选择？&quot;">​</a></h2><p>分两大类。</p><p><strong>训练时方法（改权重）：</strong></p><table tabindex="0"><thead><tr><th>方法</th><th>核心思路</th><th>关键区别</th></tr></thead><tbody><tr><td>RLHF/PPO</td><td>训练 Reward Model + 强化学习</td><td>需要 RM + Critic</td></tr><tr><td>DPO</td><td>跳过 RM，直接在偏好对上优化</td><td>更简单稳定，不需 RM</td></tr><tr><td>GRPO</td><td>同 prompt 采样一组，组内比较</td><td>不需 RM 也不需 Critic</td></tr></tbody></table><p><strong>推理时方法（不改权重）：</strong></p><ul><li>CoT：写出推理步骤，零成本提升</li><li>Self-Consistency：多条 CoT 投票，降方差</li><li>ReAct：推理和工具调用交替</li><li>Tree of Thoughts：维护推理树，可回溯搜索</li></ul><p>选择决策链：有标准答案 → GRPO + Self-Consistency；需外部交互 → ReAct；需回溯 → ToT；通用提升 → CoT + DPO。</p><h2 id="q3-pip-install-flash-attn-报-dns-错误-kaggle-上安装卡住" tabindex="-1">Q3：pip install flash-attn 报 DNS 错误 / Kaggle 上安装卡住 <a class="header-anchor" href="#q3-pip-install-flash-attn-报-dns-错误-kaggle-上安装卡住" aria-label="Permalink to &quot;Q3：pip install flash-attn 报 DNS 错误 / Kaggle 上安装卡住&quot;">​</a></h2><ul><li>DNS 错误 = Kaggle 默认关闭互联网访问，Settings 里打开即可</li><li>安装卡住 = 可能在编译 C++/CUDA 代码，Kaggle CPU 弱，且这个包学 RL 大概率用不上，建议跳过</li></ul><h2 id="q4-工作流不也能教会-ai-如何思考吗" tabindex="-1">Q4：工作流不也能教会 AI 如何思考吗？ <a class="header-anchor" href="#q4-工作流不也能教会-ai-如何思考吗" aria-label="Permalink to &quot;Q4：工作流不也能教会 AI 如何思考吗？&quot;">​</a></h2><p>关键区分：<strong>工作流是&quot;外在脚手架&quot;，微调是&quot;内化能力&quot;。</strong></p><p>工作流做不到的：</p><ol><li><strong>隐式判断</strong>——模型内部知道不对，但流程让它继续走过场</li><li><strong>自适应推理深度</strong>——简单问题和复杂问题走一样的流程</li><li><strong>步骤漂移</strong>——长对话中模型逐渐偏离你设计的流程</li><li><strong>隐性知识运用</strong>——菜谱 vs 厨师经验</li><li><strong>元认知</strong>——&quot;我觉得这个方向不太对，该回头&quot;，无法写成 if-else</li></ol><p>类比：工作流 = 棋谱（照着走），训练 = 下 10000 盘棋（内化棋感）。最好两者结合。</p><h2 id="q5-微调提供的是一种类似-灵感-或-直觉-的东西" tabindex="-1">Q5：微调提供的是一种类似&quot;灵感&quot;或&quot;直觉&quot;的东西？ <a class="header-anchor" href="#q5-微调提供的是一种类似-灵感-或-直觉-的东西" aria-label="Permalink to &quot;Q5：微调提供的是一种类似&quot;灵感&quot;或&quot;直觉&quot;的东西？&quot;">​</a></h2><p>对的。直觉的三个特征微调都对应：</p><ul><li>直觉是<strong>快的</strong>（不需显式分析）→ 微调后一次前向传播</li><li>直觉<strong>不需要理由</strong>（说不清为什么）→ 判断分布在参数里，无法追溯</li><li>直觉<strong>来自大量经验的压缩</strong> → 微调 = 把海量偏好压缩进权重</li></ul><h2 id="q6-微调、工作流、上下文分别对应灵感、显式流程、情境认知" tabindex="-1">Q6：微调、工作流、上下文分别对应灵感、显式流程、情境认知？ <a class="header-anchor" href="#q6-微调、工作流、上下文分别对应灵感、显式流程、情境认知" aria-label="Permalink to &quot;Q6：微调、工作流、上下文分别对应灵感、显式流程、情境认知？&quot;">​</a></h2><p>完全正确，三层认知模型：</p><table tabindex="0"><thead><tr><th>层</th><th>对应</th><th>回答的问题</th><th>特点</th></tr></thead><tbody><tr><td>微调</td><td>直觉/经验</td><td>&quot;感觉怎么做是对的？&quot;</td><td>快，固化在权重</td></tr><tr><td>工作流</td><td>显式流程</td><td>&quot;应该怎么做？&quot;</td><td>慢，可重新编排</td></tr><tr><td>上下文</td><td>工作记忆</td><td>&quot;现在是什么情况？&quot;</td><td>随长度衰减</td></tr></tbody></table><p>三者协同，不是竞争：</p><ul><li>只有直觉 → 拍脑袋，翻车了不知道怎么回溯</li><li>只有工作流 → 像实习生，每个判断都要翻手册</li><li>只有上下文 → 读了一堆资料但不会综合判断</li></ul><h2 id="最终答案" tabindex="-1">最终答案 <a class="header-anchor" href="#最终答案" aria-label="Permalink to &quot;最终答案&quot;">​</a></h2><p>微调不是用来装知识的（RAG 的活），也不是用来规定步骤的（工作流的活），而是用来培养让你少依赖 RAG 和 prompt 的<strong>判断力</strong>——那种不看 checklist 也能做对的&quot;肌肉记忆&quot;。</p>',29)])])}const g=a(e,[["render",i]]);export{p as __pageData,g as default};
